module top_module(
input  wire clk,
input  wire rst,
output wire [3:0] count
);reg [3:0] unused_counter_reg;

always @(posedge clk or posedge rst)
    if (rst)
        unused_counter_reg <= 4'b0000;
    else
        unused_counter_reg <= unused_counter_reg + 1;

assign count = unused_counter_reg;

endmodule
